import{c as t,Q as a,j as i,m as s}from"./chunks/framework.BBA2dIOt.js";const u=JSON.parse(`{"title":"Ember","titleTemplate":"Self-hosted RSS reader with on-device AI summaries","description":"","frontmatter":{"layout":"home","title":"Ember","titleTemplate":"Self-hosted RSS reader with on-device AI summaries","hero":{"name":"Ember","text":"A reader for people who read.","tagline":"Self-hosted RSS aggregation with an optional on-device LLM and a paper-and-ink interface. One Go binary, one container, one tab.","image":{"light":"/screenshots/hero-2-threepane-summary-dark.png","dark":"/screenshots/hero-2-threepane-summary-light.png","alt":"Ember three-pane reader with AI summary card"},"actions":[{"theme":"brand","text":"Get started","link":"/getting-started"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/brandonhon/ember"}]},"features":[{"icon":"📰","title":"Three-pane reader","details":"Sidebar of feeds and folders, the article list, and a focused reader. Keyboard navigation (j/k/r/m/s/?), drag-to-reorder."},{"icon":"🧠","title":"Local AI summaries","details":"Optional Ollama integration produces a paragraph + bullet summary for each article. Pull, swap, and tune models from the admin UI. Strips newsletter / podcast promos from the body."},{"icon":"🔎","title":"FTS5 full-text search","details":"SQLite's FTS5 powers a dedicated search view + saved searches surfaced in the sidebar. Per-article user tags filter the list down further."},{"icon":"🪶","title":"Single binary","details":"Pure-Go SQLite, embedded Svelte SPA, no CGO. A single ~25 MB binary that runs anywhere and behind any reverse proxy."},{"icon":"🎨","title":"8 themes + custom palette","details":"Auto (matches OS), Light, Dark, Solarized, Sepia, Nord, Gruvbox, High contrast, plus a custom theme that derives the rest of the palette from 3 colors you pick."},{"icon":"🔐","title":"Hardened by default","details":"argon2id passwords, SameSite=Strict cookies, CSRF double-submit, SSRF block on outbound fetches, generic error responses, govulncheck-clean stdlib."},{"icon":"📱","title":"Fever-compatible","details":"Reeder, FeedMe, and other Fever clients connect via /fever using a random per-user API token. Random tokens, not predictable hashes."},{"icon":"⚙️","title":"Live admin controls","details":"Hot-swap LLM model, tune temperature/top_p/num_ctx, manage backups + cleanup + OPML export schedules. All from Settings."},{"icon":"🚀","title":"Auto-refresh + favicon dot","details":"15-second background poll prepends new articles without a page reload. A green dot on the favicon and (N) prefix in the tab title flag unread items."},{"icon":"🔑","title":"Passkey sign-in","details":"Self-register a FIDO2 passkey per device. Sign in with Touch ID, Face ID, or a hardware key alongside (or instead of) your password."},{"icon":"📬","title":"Daily digest email","details":"Opt-in nightly summary of your fresh / unread / starred articles sent to your inbox. Pick the view, set the time in UTC, point at any SMTP relay."},{"icon":"🌐","title":"Subscribe by URL","details":"Paste the homepage URL — Ember discovers the feed by following &lt;link rel=alternate&gt; and probing common feed paths. Also recognizes YouTube channel/handle/playlist URLs and Mastodon profiles, resolving them to the right feed automatically."},{"icon":"📧","title":"Email newsletter inbox","details":"Each user gets a unique &lt;handle&gt;@&lt;your-domain&gt; address. Mail sent there lands as articles in a synthetic Newsletters feed — Substack, Beehiiv, mailchimp etc. flow through the same reader, filters, and digest. Off by default; opt-in by setting EMBER_EMAIL_DOMAIN."},{"icon":"🔔","title":"Web Push notifications","details":"Opt-in per device. VAPID keypair auto-generated and persisted; no third-party push gateway. Send-test button in Settings → Notifications. Requires a trusted TLS cert (real domain or DNS-01 with Let's Encrypt)."},{"icon":"⚖️","title":"Smart cross-feed dedup","details":"Tracking-param-stripped canonical URL + title-fingerprint clustering (48h window) collapse syndicated wire stories into one row. Click the \\"Also in N feeds\\" pill to expand the sibling list with per-feed read/star state."},{"icon":"🎯","title":"Rules engine","details":"Five actions (mark_read, star, hide, tag, add_to_board), eight match fields including feed, tags, published_at, has_image. Per-rule priority and a Preview button that counts last-7-day matches before you save."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1780370225000}`),n={name:"index.md"};function r(o,e,l,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[s("",6)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
